// usando o método construtor
const carrinho = ['Notebook', 'Mouse', 'Teclado', 'Headset', 'Monitor'];
// adicionar no final do array
carrinho.push("Teclado");
console.log(carrinho);
// remover  último valor
carrinho.pop();
console.log(carrinho);
// adicionar no início do array
carrinho.unshift("Monitor");
console.log(carrinho);
// remover o primeiro valor
carrinho.shift();
console.log(carrinho);